{
  "name": "Discoloration: The AI Art Restorer",
  "description": "A high-stakes web game where you act as a restoration expert. Upload 'corrupted' images, use Gemini 3 Pro to analyze their flaws, and Gemini 2.5 Flash to edit and restore them to their former glory.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface RestoredImage {
  id: string;
  originalUrl: string;
  currentUrl: string;
  analysis?: string;
  history: string[];
  timestamp: number;
}

export enum GameState {
  IDLE = 'IDLE',
  ANALYZING = 'ANALYZING',
  EDITING = 'EDITING',
  VIEWING = 'VIEWING'
}

import { GoogleGenAI } from "@google/genai";

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const analyzeImage = async (base64Image: string): Promise<string> => {
  const ai = getAI();
  const prompt = "Act as a professional art restoration expert. Look at this image and tell me exactly what is 'discolored', corrupted, or needs correction. Be specific and identify at least 3 areas of improvement. Keep it concise but professional.";

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: {
      parts: [
        { inlineData: { mimeType: 'image/png', data: base64Image.split(',')[1] || base64Image } },
        { text: prompt }
      ]
    }
  });

  return response.text || "No analysis available.";
};

export const editImage = async (base64Image: string, instruction: string): Promise<string> => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [
        { inlineData: { mimeType: 'image/png', data: base64Image.split(',')[1] || base64Image } },
        { text: instruction }
      ]
    }
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }

  throw new Error("Failed to generate image.");
};

import React, { useState, useCallback } from 'react';
import { Header } from './components/Header';
import { ImageUploader } from './components/ImageUploader';
import { AnalysisPanel } from './components/AnalysisPanel';
import { EditorPanel } from './components/EditorPanel';
import { Gallery } from './components/Gallery';
import { RestoredImage, GameState } from './types';
import { analyzeImage, editImage } from './geminiService';

const App: React.FC = () => {
  const [activeImage, setActiveImage] = useState<RestoredImage | null>(null);
  const [gallery, setGallery] = useState<RestoredImage[]>([]);
  const [status, setStatus] = useState<GameState>(GameState.IDLE);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleUpload = useCallback((url: string) => {
    const newImg: RestoredImage = {
      id: Date.now().toString(),
      originalUrl: url,
      currentUrl: url,
      history: [url],
      timestamp: Date.now()
    };
    setActiveImage(newImg);
    setStatus(GameState.VIEWING);
  }, []);

  const handleStartAnalysis = useCallback(async () => {
    if (!activeImage) return;
    setLoading(true);
    setError(null);
    try {
      const analysis = await analyzeImage(activeImage.currentUrl);
      setActiveImage(prev => prev ? { ...prev, analysis } : null);
      setStatus(GameState.ANALYZING);
    } catch (err) {
      setError("Failed to analyze image. Please check your API configuration.");
      console.error(err);
    } finally {
      setLoading(false);
    }
  }, [activeImage]);

  const handleApplyEdit = useCallback(async (instruction: string) => {
    if (!activeImage) return;
    setLoading(true);
    setError(null);
    try {
      const newUrl = await editImage(activeImage.currentUrl, instruction);
      const updated = {
        ...activeImage,
        currentUrl: newUrl,
        history: [...activeImage.history, newUrl]
      };
      setActiveImage(updated);
      setStatus(GameState.VIEWING);
    } catch (err) {
      setError("Restoration failed. The 'discoloration' might be too severe.");
      console.error(err);
    } finally {
      setLoading(false);
    }
  }, [activeImage]);

  const handleSaveToGallery = useCallback(() => {
    if (!activeImage) return;
    setGallery(prev => [activeImage, ...prev]);
    setActiveImage(null);
    setStatus(GameState.IDLE);
  }, [activeImage]);

  const handleReset = useCallback(() => {
    setActiveImage(null);
    setStatus(GameState.IDLE);
    setError(null);
  }, []);

  return (
    <div className="min-h-screen flex flex-col">
      <Header />

      <main className="flex-grow container mx-auto px-4 py-8 max-w-6xl">
        {error && (
          <div className="mb-6 bg-red-900/40 border border-red-500 text-red-200 px-4 py-3 rounded-xl flex items-center justify-between">
            <span>{error}</span>
            <button onClick={() => setError(null)} className="text-xl font-bold">&times;</button>
          </div>
        )}

        {status === GameState.IDLE ? (
          <div className="flex flex-col items-center justify-center py-20 space-y-8 animate-in fade-in duration-700">
            <div className="text-center space-y-4 max-w-2xl">
              <h2 className="text-4xl md:text-5xl font-bold gradient-text">Restore the Lost Colors</h2>
              <p className="text-slate-400 text-lg">
                The Discoloration has corrupted our digital heritage. As an elite AI Restoration Agent, 
                your task is to analyze anomalies and restore images using advanced neural processing.
              </p>
            </div>
            <ImageUploader onUpload={handleUpload} />

            {gallery.length > 0 && (
              <div className="w-full mt-12">
                <h3 className="text-2xl font-bold mb-6 text-slate-300">Your Restoration Archive</h3>
                <Gallery images={gallery} />
              </div>
            )}
          </div>
        ) : (
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 animate-in slide-in-from-bottom-8 duration-500">
            {/* Main Preview */}
            <div className="space-y-6">
              <div className="glass rounded-2xl overflow-hidden shadow-2xl relative aspect-square group">
                {activeImage && (
                  <img 
                    src={activeImage.currentUrl} 
                    alt="Restoration Target" 
                    className="w-full h-full object-cover"
                  />
                )}
                {loading && (
                  <div className="absolute inset-0 bg-slate-950/60 backdrop-blur-sm flex items-center justify-center z-20">
                    <div className="flex flex-col items-center space-y-4">
                      <div className="w-12 h-12 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin"></div>
                      <p className="text-indigo-300 font-medium animate-pulse">Running Neural Reconstruction...</p>
                    </div>
                  </div>
                )}
              </div>

              <div className="flex flex-wrap gap-4">
                <button 
                  onClick={handleReset}
                  className="px-6 py-3 rounded-xl bg-slate-800 hover:bg-slate-700 transition-colors font-semibold"
                >
                  Discard
                </button>
                <button 
                  onClick={handleSaveToGallery}
                  className="px-6 py-3 rounded-xl bg-indigo-600 hover:bg-indigo-500 transition-colors font-semibold shadow-lg shadow-indigo-900/20"
                >
                  Save to Archive
                </button>
              </div>
            </div>

            {/* Controls Panel */}
            <div className="space-y-6">
              {status === GameState.VIEWING && (
                <div className="glass rounded-2xl p-8 space-y-6">
                  <div className="space-y-2">
                    <h3 className="text-2xl font-bold text-indigo-300">Target Identified</h3>
                    <p className="text-slate-400">Scan the artifact to identify discoloration patterns.</p>
                  </div>
                  <button 
                    onClick={handleStartAnalysis}
                    disabled={loading}
                    className="w-full py-4 rounded-xl bg-gradient-to-r from-indigo-600 to-purple-600 hover:from-indigo-500 hover:to-purple-500 transition-all font-bold text-lg shadow-xl shadow-indigo-500/20 disabled:opacity-50"
                  >
                    Scan for Anomalies
                  </button>
                  <button 
                    onClick={() => setStatus(GameState.EDITING)}
                    className="w-full py-4 rounded-xl border border-indigo-500/30 hover:bg-indigo-500/10 transition-colors font-bold text-lg"
                  >
                    Manual Override (Edit)
                  </button>
                </div>
              )}

              {status === GameState.ANALYZING && activeImage?.analysis && (
                <AnalysisPanel 
                  analysis={activeImage.analysis} 
                  onProceed={() => setStatus(GameState.EDITING)}
                  onBack={() => setStatus(GameState.VIEWING)}
                />
              )}

              {status === GameState.EDITING && (
                <EditorPanel 
                  onApply={handleApplyEdit} 
                  onCancel={() => setStatus(GameState.VIEWING)}
                  loading={loading}
                />
              )}
            </div>
          </div>
        )}
      </main>

      <footer className="py-6 border-t border-slate-800 text-center text-slate-500 text-sm">
        Discoloration Restorer Protocol &copy; {new Date().getFullYear()} • Powered by Gemini AI
      </footer>
    </div>
  );
};

export default App;

import React, { useRef } from 'react';

interface Props {
  onUpload: (url: string) => void;
}

export const ImageUploader: React.FC<Props> = ({ onUpload }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        if (event.target?.result) {
          onUpload(event.target.result as string);
        }
      };
      reader.readAsDataURL(file);
    }
  };

  return (
    <div 
      onClick={() => fileInputRef.current?.click()}
      className="w-full max-w-md p-10 border-2 border-dashed border-slate-700 hover:border-indigo-500 rounded-3xl cursor-pointer transition-all bg-slate-900/50 flex flex-col items-center justify-center space-y-4 group"
    >
      <div className="w-16 h-16 rounded-full bg-slate-800 flex items-center justify-center group-hover:bg-indigo-900/30 transition-colors">
        <svg className="w-8 h-8 text-slate-400 group-hover:text-indigo-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
        </svg>
      </div>
      <div className="text-center">
        <p className="text-lg font-semibold text-slate-200">Initiate Restoration</p>
        <p className="text-sm text-slate-500">Select a corrupted artifact (PNG, JPG)</p>
      </div>
      <input 
        type="file" 
        ref={fileInputRef} 
        onChange={handleFileChange} 
        className="hidden" 
        accept="image/*"
      />
    </div>
  );
};

import React from 'react';

interface Props {
  analysis: string;
  onProceed: () => void;
  onBack: () => void;
}

export const AnalysisPanel: React.FC<Props> = ({ analysis, onProceed, onBack }) => {
  // Simple markdown-ish bolding for points
  const formattedAnalysis = analysis.split('\n').map((line, i) => {
    if (line.trim().startsWith('-') || line.trim().startsWith('*')) {
      return <li key={i} className="mb-2 ml-4 list-disc">{line.replace(/^[-*]\s*/, '')}</li>;
    }
    return <p key={i} className="mb-4">{line}</p>;
  });

  return (
    <div className="glass rounded-2xl p-8 space-y-6 animate-in slide-in-from-right-8 duration-500">
      <div className="flex items-center space-x-3 text-emerald-400 mb-2">
        <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" />
        </svg>
        <h3 className="text-2xl font-bold">Analysis Complete</h3>
      </div>

      <div className="prose prose-invert text-slate-300 max-h-[400px] overflow-y-auto pr-2 custom-scrollbar">
        {formattedAnalysis}
      </div>

      <div className="pt-6 space-y-3">
        <button 
          onClick={onProceed}
          className="w-full py-4 rounded-xl bg-indigo-600 hover:bg-indigo-500 transition-colors font-bold text-lg shadow-xl shadow-indigo-900/20"
        >
          Begin Restoration (Edit)
        </button>
        <button 
          onClick={onBack}
          className="w-full py-4 rounded-xl text-slate-400 hover:text-white transition-colors font-medium"
        >
          Back to Scan
        </button>
      </div>
    </div>
  );
};

import React, { useState } from 'react';

interface Props {
  onApply: (instruction: string) => void;
  onCancel: () => void;
  loading: boolean;
}

export const EditorPanel: React.FC<Props> = ({ onApply, onCancel, loading }) => {
  const [instruction, setInstruction] = useState('');

  const suggestions = [
    "Restore natural colors and contrast",
    "Remove artifacts and digital noise",
    "Add a vintage film restoration filter",
    "Fix lighting and shadow inconsistencies",
    "Enhance resolution and clarity"
  ];

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (instruction.trim()) {
      onApply(instruction);
    }
  };

  return (
    <div className="glass rounded-2xl p-8 space-y-6 animate-in slide-in-from-right-8 duration-500">
      <div className="space-y-2">
        <h3 className="text-2xl font-bold text-indigo-300">Restoration Engine</h3>
        <p className="text-slate-400">Issue direct commands to the neural reconstruction core.</p>
      </div>

      <form onSubmit={handleSubmit} className="space-y-4">
        <textarea
          value={instruction}
          onChange={(e) => setInstruction(e.target.value)}
          placeholder="e.g. 'Remove the reddish tint from the sky and sharpen the focus on the foreground subjects'"
          className="w-full h-32 bg-slate-900/80 border border-slate-700 rounded-xl p-4 text-white placeholder-slate-600 focus:outline-none focus:border-indigo-500 transition-colors resize-none"
        />

        <div className="flex flex-wrap gap-2">
          {suggestions.map((s) => (
            <button
              key={s}
              type="button"
              onClick={() => setInstruction(s)}
              className="text-xs px-3 py-1.5 rounded-full bg-slate-800 hover:bg-slate-700 text-slate-400 hover:text-white transition-all"
            >
              + {s}
            </button>
          ))}
        </div>

        <div className="pt-4 flex gap-4">
          <button
            type="submit"
            disabled={loading || !instruction.trim()}
            className="flex-grow py-4 rounded-xl bg-indigo-600 hover:bg-indigo-500 transition-colors font-bold text-lg shadow-xl shadow-indigo-900/20 disabled:opacity-50"
          >
            Execute Command
          </button>
          <button
            type="button"
            onClick={onCancel}
            className="px-6 py-4 rounded-xl border border-slate-700 hover:bg-slate-800 transition-colors font-semibold"
          >
            Cancel
          </button>
        </div>
      </form>
    </div>
  );
};

import React from 'react';
import { RestoredImage } from '../types';

interface Props {
  images: RestoredImage[];
}

export const Gallery: React.FC<Props> = ({ images }) => {
  return (
    <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-6">
      {images.map((img) => (
        <div 
          key={img.id} 
          className="glass rounded-xl overflow-hidden group hover:scale-[1.02] transition-transform shadow-lg"
        >
          <div className="aspect-square relative overflow-hidden">
            <img 
              src={img.currentUrl} 
              alt="Restored artifact" 
              className="w-full h-full object-cover" 
            />
            <div className="absolute inset-0 bg-gradient-to-t from-slate-950/80 to-transparent opacity-0 group-hover:opacity-100 transition-opacity flex items-end p-4">
              <span className="text-xs text-indigo-300 font-bold uppercase tracking-wider">Restored Artifact</span>
            </div>
          </div>
          <div className="p-4 border-t border-slate-800">
            <div className="flex items-center justify-between text-[10px] text-slate-500 uppercase font-bold tracking-widest">
              <span>{new Date(img.timestamp).toLocaleDateString()}</span>
              <span className="text-emerald-500">CLEAN</span>
            </div>
          </div>
        </div>
      ))}
    </div>
  );
};

export interface GameState {
  grid: boolean[][];
  size: number;
  level: number;
  moves: number;
  isWon: boolean;
  status: 'playing' | 'analyzing' | 'won';
  hint?: string;
}

import { GoogleGenAI } from "@google/genai";

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getPuzzleHint = async (grid: boolean[][], size: number): Promise<string> => {
  const ai = getAI();
  const gridString = grid.map(row => row.map(cell => cell ? '1' : '0').join('')).join('\n');

  const prompt = `You are the Discoloration Matrix Assistant. 
  The player is in a ${size}x${size} grid puzzle. 
  The goal is to turn all cells to '1' (Colored). 
  Clicking a cell toggles it and its neighbors (U,D,L,R).

  Current Board State (0 = off, 1 = colored):
  ${gridString}

  Provide a short, cryptic, hacker-style hint for the next move. Don't give the full solution, just a push in the right direction. Keep it under 20 words.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [{ text: prompt }]
    });
    return response.text || "Neural link unstable. Focus on the corners.";
  } catch (err) {
    return "The matrix is shifting. Use your intuition.";
  }
};

import React, { useState, useEffect, useCallback } from 'react';
import { Header } from './components/Header';
import { getPuzzleHint } from './geminiService';
import { GameState } from './types';

const App: React.FC = () => {
  const [game, setGame] = useState<GameState>({
    grid: [],
    size: 3,
    level: 1,
    moves: 0,
    isWon: false,
    status: 'playing'
  });
  const [loadingHint, setLoadingHint] = useState(false);

  // Initialize grid (all false/uncolored as requested)
  const initGrid = useCallback((size: number) => {
    const newGrid = Array(size).fill(null).map(() => Array(size).fill(false));
    return newGrid;
  }, []);

  useEffect(() => {
    setGame(prev => ({ ...prev, grid: initGrid(prev.size) }));
  }, [initGrid]);

  const toggleCell = (r: number, c: number) => {
    if (game.status !== 'playing') return;

    setGame(prev => {
      const newGrid = prev.grid.map(row => [...row]);
      const targets = [
        [r, c], [r - 1, c], [r + 1, c], [r, c - 1], [r, c + 1]
      ];

      targets.forEach(([tr, tc]) => {
        if (tr >= 0 && tr < prev.size && tc >= 0 && tc < prev.size) {
          newGrid[tr][tc] = !newGrid[tr][tc];
        }
      });

      const isWon = newGrid.every(row => row.every(cell => cell === true));
      return {
        ...prev,
        grid: newGrid,
        moves: prev.moves + 1,
        isWon,
        status: isWon ? 'won' : 'playing'
      };
    });
  };

  const handleNextLevel = () => {
    const nextSize = game.size + (game.level % 2 === 0 ? 1 : 0); // Increase size every 2 levels
    setGame({
      grid: initGrid(nextSize),
      size: nextSize,
      level: game.level + 1,
      moves: 0,
      isWon: false,
      status: 'playing',
      hint: undefined
    });
  };

  const handleGetHint = async () => {
    setLoadingHint(true);
    const hint = await getPuzzleHint(game.grid, game.size);
    setGame(prev => ({ ...prev, hint }));
    setLoadingHint(false);
  };

  const resetLevel = () => {
    setGame(prev => ({
      ...prev,
      grid: initGrid(prev.size),
      moves: 0,
      isWon: false,
      status: 'playing',
      hint: undefined
    }));
  };

  return (
    <div className="min-h-screen flex flex-col bg-[#050505] text-slate-100 selection:bg-indigo-500/30">
      <Header />

      <main className="flex-grow flex flex-col items-center justify-center p-4">
        {/* Game Stats */}
        <div className="w-full max-w-md flex justify-between items-end mb-8 px-2">
          <div>
            <p className="text-xs font-bold text-indigo-500 tracking-[0.2em] uppercase mb-1">Sector</p>
            <p className="text-4xl font-black text-white">{game.level.toString().padStart(2, '0')}</p>
          </div>
          <div className="text-right">
            <p className="text-xs font-bold text-indigo-500 tracking-[0.2em] uppercase mb-1">Shifts</p>
            <p className="text-4xl font-mono font-bold text-white">{game.moves}</p>
          </div>
        </div>

        {/* The Grid */}
        <div 
          className="grid gap-2 p-4 glass rounded-2xl shadow-[0_0_50px_rgba(79,70,229,0.1)] mb-8"
          style={{ 
            gridTemplateColumns: `repeat(${game.size}, minmax(0, 1fr))`,
            width: '100%',
            maxWidth: 'min(90vw, 500px)',
            aspectRatio: '1/1'
          }}
        >
          {game.grid.map((row, r) => 
            row.map((cell, c) => (
              <button
                key={`${r}-${c}`}
                onClick={() => toggleCell(r, c)}
                className={`
                  relative rounded-lg transition-all duration-300 transform active:scale-95
                  ${cell 
                    ? 'bg-gradient-to-br from-indigo-500 to-cyan-400 shadow-[0_0_20px_rgba(99,102,241,0.6)] border-transparent' 
                    : 'bg-slate-900 border border-slate-800 hover:border-slate-600'
                  }
                `}
              >
                {cell && (
                  <div className="absolute inset-0 bg-white/20 animate-pulse rounded-lg" />
                )}
              </button>
            ))
          )}
        </div>

        {/* Controls */}
        <div className="w-full max-w-md space-y-4">
          {game.status === 'won' ? (
            <button 
              onClick={handleNextLevel}
              className="w-full py-5 rounded-2xl bg-indigo-600 hover:bg-indigo-500 text-white font-black text-xl tracking-widest shadow-2xl shadow-indigo-500/40 animate-bounce"
            >
              NEXT SECTOR
            </button>
          ) : (
            <div className="grid grid-cols-2 gap-4">
              <button 
                onClick={resetLevel}
                className="py-4 rounded-xl border border-slate-800 hover:bg-slate-900 text-slate-400 font-bold transition-colors"
              >
                REBOOT
              </button>
              <button 
                onClick={handleGetHint}
                disabled={loadingHint}
                className="py-4 rounded-xl bg-slate-900 hover:bg-slate-800 text-indigo-400 font-bold border border-indigo-500/20 flex items-center justify-center gap-2"
              >
                {loadingHint ? (
                  <div className="w-4 h-4 border-2 border-indigo-400 border-t-transparent rounded-full animate-spin" />
                ) : (
                  <>
                    <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
                    </svg>
                    SCAN
                  </>
                )}
              </button>
            </div>
          )}

          {game.hint && !game.isWon && (
            <div className="p-4 glass rounded-xl border-indigo-500/20 animate-in fade-in slide-in-from-top-2">
              <p className="text-xs font-bold text-indigo-400 uppercase tracking-widest mb-1">Neural Advice</p>
              <p className="text-slate-300 italic">"{game.hint}"</p>
            </div>
          )}
        </div>
      </main>

      {/* Win Overlay */}
      {game.isWon && (
        <div className="fixed inset-0 z-[100] bg-indigo-600/10 backdrop-blur-sm pointer-events-none flex items-center justify-center animate-in fade-in zoom-in duration-500">
           <div className="text-center">
             <h2 className="text-7xl font-black text-white italic tracking-tighter drop-shadow-2xl">DISCOLORED</h2>
             <p className="text-indigo-300 font-bold tracking-[0.5em] uppercase">Sector Sanitized</p>
           </div>
        </div>
