export interface GameState {
  grid: boolean[][];
  size: number;
  level: number;
  moves: number;
  isWon: boolean;
  status: 'playing' | 'analyzing' | 'won';
  hint?: {
    message: string;
    targetCell?: [number, number];
    distance?: number;
  };
}

export interface RestoredImage {
  id: string;
  originalUrl: string;
  currentUrl: string;
  timestamp: number;
  prompt?: string;
}

export interface SolverResult {
  minMoves: number;
  clickPositions: [number, number][];
}

export function solveLightsOut(grid: boolean[][], N: number): SolverResult | null {
  const ALL_ON = (1 << N) - 1;
  let best = Infinity;
  let bestMoves: number[] = [];

  const initialRows: number[] = grid.map(row => {
    let rowVal = 0;
    row.forEach((cell, c) => {
      if (cell) rowVal |= (1 << c);
    });
    return rowVal;
  });

  const getToggled = (r: number, c: number, currentGrid: number[]) => {
    const dr = [0, 0, 0, 1, -1];
    const dc = [0, 1, -1, 0, 0];
    const nextGrid = [...currentGrid];

    for (let k = 0; k < 5; k++) {
      const nr = r + dr[k];
      const nc = c + dc[k];
      if (nr >= 0 && nr < N && nc >= 0 && nc < N) {
        nextGrid[nr] ^= (1 << nc);
      }
    }
    return nextGrid;
  };

  for (let mask = 0; mask < (1 << N); mask++) {
    let currentGrid = [...initialRows];
    let moves = new Array(N).fill(0);
    let cnt = 0;

    // First row decisions based on bitmask
    for (let c = 0; c < N; c++) {
      if (mask & (1 << c)) {
        currentGrid = getToggled(0, c, currentGrid);
        moves[0] |= (1 << c);
        cnt++;
      }
    }

    // Propagate downward greedily
    for (let r = 1; r < N; r++) {
      for (let c = 0; c < N; c++) {
        // If the cell in the previous row is OFF, we MUST toggle the cell below it
        if (!(currentGrid[r - 1] & (1 << c))) {
          currentGrid = getToggled(r, c, currentGrid);
          moves[r] |= (1 << c);
          cnt++;
        }
      }
    }

    // Check if the last row is fully ON
    if (currentGrid[N - 1] === ALL_ON) {
      if (cnt < best) {
        best = cnt;
        bestMoves = [...moves];
      }
    }
  }

  if (best === Infinity) return null;

  const clickPositions: [number, number][] = [];
  for (let r = 0; r < N; r++) {
    for (let c = 0; c < N; c++) {
      if (bestMoves[r] & (1 << c)) {
        clickPositions.push([r, c]);
      }
    }
  }

  return { minMoves: best, clickPositions };
}

