interface ExtendedGameState extends GameState {
  view: 'playing' | 'summary';
  optimalForLevel: number;
}

const App: React.FC = () => {
  const [game, setGame] = useState<ExtendedGameState>({
    grid: [],
    size: 3,
    level: 1,
    moves: 0,
    isWon: false,
    status: 'playing',
    view: 'playing',
    optimalForLevel: 0
  });
  const [history, setHistory] = useState<boolean[][][]>([]);
  const [loadingHint, setLoadingHint] = useState(false);

  // Initialize grid (all false/uncolored)
  const initGrid = useCallback((size: number) => {
    const grid = Array(size).fill(null).map(() => Array(size).fill(false));
    const solution = solveLightsOut(grid, size);
    return { grid, optimal: solution?.minMoves || 0 };
  }, []);

  // Initial setup
  useEffect(() => {
    const { grid, optimal } = initGrid(game.size);
    setGame(prev => ({ 
      ...prev, 
      grid, 
      optimalForLevel: optimal,
      moves: 0,
      isWon: false,
      status: 'playing',
      view: 'playing'
    }));
    setHistory([]);
  }, []);

  const handleNextLevel = useCallback(() => {
    setGame(prev => {
      const nextSize = prev.size + (prev.level % 2 === 0 ? 1 : 0);
      const { grid, optimal } = initGrid(nextSize);
      return {
        ...prev,
        grid,
        size: nextSize,
        level: prev.level + 1,
        moves: 0,
        isWon: false,
        status: 'playing',
        view: 'playing',
        optimalForLevel: optimal,
        hint: undefined
      };
    });
    setHistory([]);
  }, [initGrid]);

  const toggleCell = (r: number, c: number) => {
    if (game.status !== 'playing' || game.view !== 'playing') return;

    setGame(prev => {
      // Save current state to history
      setHistory(oldHistory => [...oldHistory, prev.grid.map(row => [...row])]);

      const newGrid = prev.grid.map(row => [...row]);
      const targets = [
        [r, c], [r - 1, c], [r + 1, c], [r, c - 1], [r, c + 1]
      ];

      targets.forEach(([tr, tc]) => {
        if (tr >= 0 && tr < prev.size && tc >= 0 && tc < prev.size) {
          newGrid[tr][tc] = !newGrid[tr][tc];
        }
      });

      const isWon = newGrid.every(row => row.every(cell => cell === true));

      if (isWon) {
        return {
          ...prev,
          grid: newGrid,
          moves: prev.moves + 1,
          isWon: true,
          status: 'won',
          view: 'summary',
          hint: undefined
        };
      }

      return {
        ...prev,
        grid: newGrid,
        moves: prev.moves + 1,
        isWon: false,
        status: 'playing',
        hint: undefined
      };
    });
  };

  const handleUndo = () => {
    if (history.length === 0 || game.view !== 'playing') return;
    setHistory(oldHistory => {
      const lastState = oldHistory[oldHistory.length - 1];
      setGame(prev => ({
        ...prev,
        grid: lastState,
        moves: Math.max(0, prev.moves - 1),
        hint: undefined
      }));
      return oldHistory.slice(0, -1);
    });
  };

  const handleGetHint = () => {
    setLoadingHint(true);
    const solution = solveLightsOut(game.grid, game.size);
    if (!solution || solution.clickPositions.length === 0) {
      setGame(prev => ({ 
        ...prev, 
        hint: { message: "Matrix parity unrecoverable." } 
      }));
      setLoadingHint(false);
      return;
    }
    setGame(prev => ({ 
      ...prev, 
      hint: { 
        message: "Sector localized.",
        targetCell: solution.clickPositions[0],
        distance: solution.minMoves
      } 
    }));
    setLoadingHint(false);
  };

  const resetLevel = () => {
    const { grid, optimal } = initGrid(game.size);
    setGame(prev => ({
      ...prev,
      grid,
      moves: 0,
      isWon: false,
      status: 'playing',
      view: 'playing',
