import React, { useState, useEffect, useCallback } from 'react';
import { Header } from './components/Header';
import { solveLightsOut } from './solver';
import { GameState } from './types';

interface ExtendedGameState extends GameState {
  view: 'playing' | 'summary';
  optimalForLevel: number;
}

const App: React.FC = () => {
  const [game, setGame] = useState<ExtendedGameState>({
    grid: [],
    size: 3,
    level: 1,
    moves: 0,
    isWon: false,
    status: 'playing',
    view: 'playing',
    optimalForLevel: 0
  });
  const [history, setHistory] = useState<boolean[][][]>([]);
  const [loadingHint, setLoadingHint] = useState(false);

  /**
   * Generates a clean grid where all boxes are uncolored (false).
   * Calculates the optimal moves to reach the all-colored state from this start.
   */
  const createLevel = useCallback((size: number, level: number) => {
    const grid = Array(size).fill(null).map(() => Array(size).fill(false));
    const solution = solveLightsOut(grid, size);

    return {
      grid,
      size,
      level,
      optimal: solution?.minMoves || 0,
      moves: 0,
      isWon: false,
      status: 'playing' as const,
      view: 'playing' as const,
      hint: undefined
    };
  }, []);

  // Initial setup for Level 1 (3x3)
  useEffect(() => {
    const newLevel = createLevel(3, 1);
    setGame(prev => ({ 
      ...prev, 
      ...newLevel,
      optimalForLevel: newLevel.optimal
    }));
    setHistory([]);
  }, [createLevel]);

  const handleNextLevel = useCallback(() => {
    setGame(prev => {
      const nextSize = prev.size + 1;
      const nextLevelNum = prev.level + 1;
      const newLevel = createLevel(nextSize, nextLevelNum);

      return {
        ...prev,
        ...newLevel,
        optimalForLevel: newLevel.optimal
      };
    });
    setHistory([]);
  }, [createLevel]);

  const toggleCell = (r: number, c: number) => {
    if (game.status !== 'playing' || game.view !== 'playing') return;

    setGame(prev => {
      // Save current state to history before changing
      setHistory(oldHistory => [...oldHistory, prev.grid.map(row => [...row])]);

      const newGrid = prev.grid.map(row => [...row]);
      const targets = [
        [r, c], [r - 1, c], [r + 1, c], [r, c - 1], [r, c + 1]
      ];

      targets.forEach(([tr, tc]) => {
        if (tr >= 0 && tr < prev.size && tc >= 0 && tc < prev.size) {
          newGrid[tr][tc] = !newGrid[tr][tc];
        }
      });

      const isWon = newGrid.every(row => row.every(cell => cell === true));

      if (isWon) {
        return {
          ...prev,
          grid: newGrid,
          moves: prev.moves + 1,
          isWon: true,
          status: 'won',
          view: 'summary',
          hint: undefined
        };
      }

      return {
        ...prev,
        grid: newGrid,
        moves: prev.moves + 1,
        isWon: false,
        status: 'playing',
        hint: undefined
      };
    });
  };

  const handleUndo = () => {
    if (history.length === 0 || game.view !== 'playing') return;
    setHistory(oldHistory => {
      const lastState = oldHistory[oldHistory.length - 1];
      setGame(prev => ({
        ...prev,
        grid: lastState,
        moves: Math.max(0, prev.moves - 1),
        hint: undefined
      }));
      return oldHistory.slice(0, -1);
    });
  };

  const handleGetHint = () => {
    setLoadingHint(true);
    const solution = solveLightsOut(game.grid, game.size);
    if (!solution || solution.clickPositions.length === 0) {
      setGame(prev => ({ 
        ...prev, 
        hint: { message: "No solution possible from this state." } 
      }));
      setLoadingHint(false);
      return;
    }
    setGame(prev => ({ 
      ...prev, 
      hint: { 
        message: "Recommended sector highlighted.",
        targetCell: solution.clickPositions[0],
        distance: solution.minMoves
      } 
    }));
    setLoadingHint(false);
  };

  const resetLevel = () => {
    const newLevel = createLevel(game.size, game.level);
    setGame(prev => ({
      ...prev,
      ...newLevel,
      optimalForLevel: newLevel.optimal
    }));
    setHistory([]);
  };

  if (game.view === 'summary') {
    return (
      <div className="min-h-screen flex flex-col text-slate-100 selection:bg-indigo-500/30">
        <Header />
        <main className="flex-grow flex flex-col items-center justify-center p-4 animate-in fade-in zoom-in duration-500">
          <div className="w-full max-w-md glass rounded-[3rem] p-10 border-white/10 shadow-[0_0_100px_rgba(79,70,229,0.2)] text-center">
            <h2 className="text-5xl font-black text-white italic tracking-tighter mb-2">COMPLETE</h2>
            <p className="text-indigo-400 font-bold tracking-[0.4em] uppercase text-xs mb-10">Level {game.level} Resolved</p>

            <div className="grid grid-cols-2 gap-6 mb-12">
              <div className="bg-slate-900/40 p-6 rounded-3xl border border-white/5">
                <p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-1">Your Shifts</p>
                <p className="text-4xl font-black text-white">{game.moves}</p>
              </div>
              <div className="bg-indigo-500/10 p-6 rounded-3xl border border-indigo-500/20">
                <p className="text-[10px] font-bold text-indigo-400 uppercase tracking-widest mb-1">Optimal</p>
                <p className="text-4xl font-black text-indigo-300">
                  {game.optimalForLevel > 0 ? game.optimalForLevel : "N/A"}
                </p>
              </div>
            </div>

            <div className="space-y-4">
              <button 
                onClick={handleNextLevel}
                className="w-full py-5 rounded-2xl bg-indigo-600 hover:bg-indigo-500 text-white font-black text-xl tracking-widest shadow-[0_0_30px_rgba(79,70,229,0.3)] transition-all active:scale-95"
              >
                NEXT LEVEL
              </button>
              <button 
                onClick={resetLevel}
                className="w-full py-4 rounded-2xl border border-slate-800 hover:bg-slate-800/50 text-slate-400 hover:text-white font-bold transition-all text-xs uppercase tracking-widest"
              >
                Replay Level
              </button>
            </div>
          </div>
        </main>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col text-slate-100 selection:bg-indigo-500/30">
      <Header />

      <main className="flex-grow flex flex-col items-center justify-center p-4">
        {/* Game Stats */}
        <div className="w-full max-w-md flex justify-between items-end mb-8 px-4">
          <div className="glass px-4 py-2 rounded-xl border-indigo-500/20">
            <p className="text-[10px] font-bold text-indigo-400 tracking-[0.2em] uppercase">Level</p>
            <p className="text-3xl font-black text-white">{game.level.toString().padStart(2, '0')}</p>
          </div>
          <div className="text-right glass px-4 py-2 rounded-xl border-indigo-500/20">
            <p className="text-[10px] font-bold text-indigo-400 tracking-[0.2em] uppercase">Shifts</p>
            <p className="text-3xl font-mono font-bold text-white">{game.moves}</p>
          </div>
        </div>

        {/* The Grid */}
        <div 
          className="grid gap-3 p-6 glass rounded-3xl shadow-[0_0_80px_rgba(79,70,229,0.12)] mb-8 border-white/5"
          style={{ 
            gridTemplateColumns: `repeat(${game.size}, minmax(0, 1fr))`,
            width: '100%',
            maxWidth: 'min(90vw, 450px)',
            aspectRatio: '1/1'
          }}
        >
          {game.grid.map((row, r) => 
            row.map((cell, c) => {
              const isTarget = game.hint?.targetCell?.[0] === r && game.hint?.targetCell?.[1] === c;
              return (
                <button
                  key={`${r}-${c}`}
                  onClick={() => toggleCell(r, c)}
                  className={`
                    relative rounded-2xl transition-all duration-500 transform active:scale-90 overflow-hidden
                    ${cell 
                      ? 'bg-gradient-to-br from-indigo-500 to-cyan-400 shadow-[0_0_25px_rgba(99,102,241,0.5)] border-transparent' 
                      : 'bg-slate-900/60 border border-slate-800 hover:border-slate-600'
                    }
                    ${isTarget ? 'target-pulse border-white' : ''}
                  `}
                >
                  <div className={`absolute inset-0 bg-white/10 transition-opacity duration-500 ${cell ? 'opacity-100' : 'opacity-0'}`} />
                  {isTarget && (
                    <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                       <div className="w-2.5 h-2.5 rounded-full bg-white shadow-[0_0_15px_white] border-2 border-indigo-500" />
                    </div>
                  )}
                </button>
              );
            })
          )}
        </div>

        {/* Controls */}
        <div className="w-full max-w-md space-y-4 px-2">
          <div className="grid grid-cols-2 gap-4">
            <button 
              onClick={resetLevel}
              className="py-4 rounded-2xl border border-slate-800 hover:bg-slate-800/50 text-slate-500 hover:text-white font-bold transition-all text-xs uppercase tracking-widest"
            >
              Reset Matrix
            </button>
            <button 
              onClick={handleUndo}
              disabled={history.length === 0}
              className="py-4 rounded-2xl border border-slate-800 hover:bg-slate-800/50 text-slate-500 hover:text-white font-bold transition-all text-xs uppercase tracking-widest disabled:opacity-20 disabled:cursor-not-allowed"
            >
              Undo
            </button>
          </div>

          <button 
            onClick={handleGetHint}
            disabled={loadingHint}
            className="w-full py-5 rounded-2xl bg-indigo-600/10 hover:bg-indigo-600/20 text-indigo-300 font-bold border border-indigo-500/30 flex items-center justify-center gap-2 transition-all text-sm uppercase tracking-widest"
          >
            {loadingHint ? (
              <div className="w-5 h-5 border-2 border-indigo-400 border-t-transparent rounded-full animate-spin" />
            ) : (
              <>
                <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
                </svg>
                Hint
