};

export default App;

import React, { useState, useEffect, useCallback } from 'react';
import { Header } from './components/Header';
import { solveLightsOut } from './solver';
import { GameState, LevelStat } from './types';

interface ExtendedGameState extends GameState {
  view: 'home' | 'playing' | 'summary';
  optimalForLevel: number;
}

const MAX_LEVEL = 10; // Up to 10x10 grid

const App: React.FC = () => {
  const [theme, setTheme] = useState<'light' | 'dark'>('light');
  const [levelStats, setLevelStats] = useState<Record<number, LevelStat>>({});
  const [game, setGame] = useState<ExtendedGameState>({
    grid: [],
    size: 3,
    level: 3,
    moves: 0,
    isWon: false,
    status: 'playing',
    view: 'home',
    optimalForLevel: 0
  });
  const [history, setHistory] = useState<boolean[][][]>([]);
  const [loadingHint, setLoadingHint] = useState(false);

  // Load stats from LocalStorage
  useEffect(() => {
    const saved = localStorage.getItem('discoloration_stats');
    const initialStats: Record<number, LevelStat> = {};

    // Initialize stats for all supported levels (3x3 to 10x10)
    for (let i = 3; i <= MAX_LEVEL; i++) {
      initialStats[i] = {
        level: i,
        bestMoves: null,
        optimalMoves: 0, 
        completed: false
      };
    }

    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setLevelStats({ ...initialStats, ...parsed });
      } catch (e) {
        setLevelStats(initialStats);
      }
    } else {
      setLevelStats(initialStats);
    }
  }, []);

  // Save stats to LocalStorage
  useEffect(() => {
    if (Object.keys(levelStats).length > 0) {
      localStorage.setItem('discoloration_stats', JSON.stringify(levelStats));
    }
  }, [levelStats]);

  const toggleTheme = () => {
    const newTheme = theme === 'light' ? 'dark' : 'light';
    setTheme(newTheme);
    document.body.className = `${newTheme === 'light' ? 'theme-light' : 'theme-dark'} bg-matrix`;
  };

  const createLevel = useCallback((size: number) => {
    // Generate a solvable grid
    // For simplicity in this game, we start from all OFF and try to turn all ON.
    // The solveLightsOut function calculates the optimal steps to turn all ON from the current state.
    const grid = Array(size).fill(null).map(() => Array(size).fill(false));
    const solution = solveLightsOut(grid, size);
    const optimalMoves = solution?.minMoves || 0;

    // Update optimal moves in stats tracking
    setLevelStats(prev => ({
      ...prev,
      [size]: {
        ...prev[size],
        optimalMoves: optimalMoves
      }
    }));

    return {
      grid,
      size,
      level: size,
      optimal: optimalMoves,
      moves: 0,
      isWon: false,
      status: 'playing' as const,
      view: 'playing' as const,
      hint: undefined
    };
  }, []);

  const selectLevel = (size: number) => {
    const newLevel = createLevel(size);
    setGame(prev => ({ 
      ...prev, 
      ...newLevel,
      optimalForLevel: newLevel.optimal
    }));
    setHistory([]);
  };

  const toggleCell = (r: number, c: number) => {
    if (game.status !== 'playing' || game.view !== 'playing') return;

    setGame(prev => {
      setHistory(oldHistory => [...oldHistory, prev.grid.map(row => [...row])]);

      const newGrid = prev.grid.map(row => [...row]);
      const targets = [
        [r, c], [r - 1, c], [r + 1, c], [r, c - 1], [r, c + 1]
      ];

      targets.forEach(([tr, tc]) => {
        if (tr >= 0 && tr < prev.size && tc >= 0 && tc < prev.size) {
          newGrid[tr][tc] = !newGrid[tr][tc];
        }
      });

      const isWon = newGrid.every(row => row.every(cell => cell === true));
      const newMoves = prev.moves + 1;

      if (isWon) {
        // Update level stats on win
        setLevelStats(currentStats => {
          const stats = currentStats[prev.size];
          const newBest = stats.bestMoves === null ? newMoves : Math.min(stats.bestMoves, newMoves);
          return {
            ...currentStats,
            [prev.size]: {
              ...stats,
              completed: true,
              bestMoves: newBest
            }
          };
        });

        return {
          ...prev,
          grid: newGrid,
          moves: newMoves,
          isWon: true,
          status: 'won',
          view: 'summary',
          hint: undefined
        };
      }

      return {
        ...prev,
        grid: newGrid,
        moves: newMoves,
        isWon: false,
        status: 'playing',
        hint: undefined
      };
    });
  };

  const handleUndo = () => {
    if (history.length === 0 || game.view !== 'playing') return;
    setHistory(oldHistory => {
      const lastState = oldHistory[oldHistory.length - 1];
      setGame(prev => ({
        ...prev,
        grid: lastState,
        moves: Math.max(0, prev.moves - 1),
        hint: undefined
      }));
      return oldHistory.slice(0, -1);
    });
  };

  const handleGetHint = () => {
    setLoadingHint(true);
    const solution = solveLightsOut(game.grid, game.size);
    if (!solution || solution.clickPositions.length === 0) {
      setGame(prev => ({ 
        ...prev, 
        hint: { message: "Current state is unrecoverable." } 
      }));
      setLoadingHint(false);
      return;
    }
    setGame(prev => ({ 
      ...prev, 
      hint: { 
        message: "Optimal shift identified.",
        targetCell: solution.clickPositions[0],
        distance: solution.minMoves
      } 
    }));
    setLoadingHint(false);
  };

  const resetLevel = () => {
    const newLevel = createLevel(game.size);
    setGame(prev => ({
      ...prev,
      ...newLevel,
      optimalForLevel: newLevel.optimal
    }));
    setHistory([]);
  };

  const goHome = () => {
    setGame(prev => ({ ...prev, view: 'home' }));
  };

  const handleNextLevel = () => {
    const nextSize = game.size + 1;
    if (nextSize <= MAX_LEVEL) {
      selectLevel(nextSize);
    } else {
      goHome();
    }
  };

  const isDark = theme === 'dark';

  if (game.view === 'home') {
    return (
      <div className={`min-h-screen flex flex-col transition-colors duration-500 ${isDark ? 'text-white' : 'text-slate-900'}`}>
        <Header theme={theme} onToggleTheme={toggleTheme} />
        <main className="flex-grow flex flex-col items-center p-6">
          <div className="w-full max-w-5xl">
            <div className="mb-12 text-center">
              <h2 className={`text-6xl font-black italic tracking-tighter mb-4 ${isDark ? 'text-indigo-400' : 'text-amber-900'}`}>
                MATRIX SECTORS
              </h2>
              <p className={`${isDark ? 'text-indigo-300' : 'text-amber-600'} font-bold tracking-[0.4em] uppercase text-xs`}>
                Select an authorized coordinate for restoration
              </p>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
              {Object.values(levelStats).map((stat) => {
                const prevLevel = levelStats[stat.level - 1];
                const isUnlocked = stat.level === 3 || (prevLevel && prevLevel.completed);
                const isOptimal = stat.bestMoves !== null && stat.bestMoves <= stat.optimalMoves;

                let cardBorder = isDark ? 'border-indigo-500/20 shadow-indigo-500/5' : 'border-amber-500/10 shadow-amber-500/5';
                let accentText = isDark ? 'text-indigo-400' : 'text-amber-700';

                if (stat.completed) {
                  accentText = isOptimal ? 'text-emerald-500' : 'text-rose-500';
                  cardBorder = isOptimal 
                    ? (isDark ? ' border-emerald-500/40 bg-emerald-500/5' : ' border-emerald-500/40 bg-emerald-50/50')
                    : (isDark ? ' border-rose-500/40 bg-rose-500/5' : ' border-rose-500/40 bg-rose-50/50');
                }

                return (
                  <button
                    key={stat.level}
                    disabled={!isUnlocked}
                    onClick={() => selectLevel(stat.level)}
                    className={`glass p-8 rounded-[2.5rem] text-left transition-all relative overflow-hidden group border-2 ${cardBorder} ${
                      isUnlocked ? 'hover:scale-[1.03] cursor-pointer' : 'opacity-40 grayscale cursor-not-allowed'
                    }`}
                  >
                    <div className="relative z-10">
                      <div className="flex justify-between items-start mb-4">
                        <span className={`text-[10px] font-black tracking-widest uppercase ${accentText}`}>
                          System {stat.level}
                        </span>
                        {!isUnlocked && (
                          <svg className="w-4 h-4 text-slate-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" />
                          </svg>
                        )}
                        {stat.completed && isOptimal && (
                          <div className="flex items-center space-x-1">
                            <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse" />
                            <span className="text-emerald-500 text-[10px] font-black uppercase">PERFECT</span>
                          </div>
                        )}
                      </div>

                      <h3 className={`text-5xl font-black mb-6 ${isDark ? 'text-white' : 'text-slate-900'}`}>
                        {stat.level}<span className="text-xl opacity-30 px-1">×</span>{stat.level}
                      </h3>

                      <div className="space-y-2">
                        <div className="flex justify-between items-center">
                          <span className="text-[10px] font-bold uppercase tracking-widest text-slate-400">Best</span>
                          <span className={`text-sm font-black ${stat.bestMoves !== null ? (isOptimal ? 'text-emerald-500' : 'text-rose-500') : (isDark ? 'text-slate-600' : 'text-slate-300')}`}>
                            {stat.bestMoves !== null ? stat.bestMoves : '--'}
                          </span>
                        </div>
                        <div className="flex justify-between items-center">
                          <span className="text-[10px] font-bold uppercase tracking-widest text-slate-400">Target</span>
                          <span className={`text-sm font-black ${isDark ? 'text-indigo-400/50' : 'text-amber-600/50'}`}>
                            {stat.optimalMoves || '??'}
                          </span>
                        </div>
                      </div>
                    </div>
                  </button>
                );
              })}
            </div>
          </div>
        </main>
      </div>
    );
  }

  if (game.view === 'summary') {
    const isOptimal = game.moves <= game.optimalForLevel;
    const accentColorClass = isOptimal ? 'emerald' : 'rose';
    const hasNext = game.size < MAX_LEVEL;

    return (
      <div className={`min-h-screen flex flex-col transition-colors duration-500 ${isDark ? 'text-white' : 'text-slate-900'}`}>
        <Header theme={theme} onToggleTheme={toggleTheme} />
        <main className="flex-grow flex flex-col items-center justify-center p-4 animate-in fade-in zoom-in duration-500">
          <div className={`w-full max-w-md glass rounded-[3rem] p-10 text-center shadow-2xl border-2 ${
            isOptimal 
              ? (isDark ? 'border-emerald-500/40 shadow-emerald-500/10' : 'border-emerald-500/30 shadow-emerald-500/10')
              : (isDark ? 'border-rose-500/40 shadow-rose-500/10' : 'border-rose-500/30 shadow-rose-500/10')
          }`}>
            <h2 className={`text-6xl font-black italic tracking-tighter mb-2 ${isDark ? `text-${accentColorClass}-400` : `text-${accentColorClass}-900`}`}>
              {isOptimal ? 'PERFECT' : 'SUCCESS'}
            </h2>
            <p className={`${isDark ? `text-${accentColorClass}-300` : `text-${accentColorClass}-600`} font-bold tracking-[0.4em] uppercase text-[10px] mb-10`}>
              Grid {game.level}x{game.level} Restored
            </p>

            <div className="grid grid-cols-2 gap-4 mb-12">
              <div className={`p-6 rounded-3xl border shadow-sm ${
                isDark ? 'bg-slate-900/50 border-slate-700' : 'bg-white border-slate-200'
              }`}>
                <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">Your Execution</p>
                <p className={`text-4xl font-black ${isDark ? 'text-white' : 'text-slate-900'}`}>{game.moves}</p>
              </div>
              <div className={`p-6 rounded-3xl border ${
                isDark ? `bg-${accentColorClass}-900/20 border-${accentColorClass}-500/30` : `bg-${accentColorClass}-50 border-${accentColorClass}-200`
              }`}>
                <p className={`text-[9px] font-black uppercase tracking-widest mb-1 ${isDark ? `text-${accentColorClass}-400` : `text-${accentColorClass}-600`}`}>Optimal Range</p>
                <p className={`text-4xl font-black ${isDark ? `text-${accentColorClass}-400` : `text-${accentColorClass}-900`}`}>
                  {game.optimalForLevel}
                </p>
              </div>
            </div>

            <div className="space-y-4">
              {hasNext && (
                <button 
                  onClick={handleNextLevel}
                  className={`w-full py-5 rounded-2xl font-black text-xl tracking-widest transition-all active:scale-95 shadow-xl ${
                    isDark 
                      ? 'bg-indigo-600 hover:bg-indigo-500 text-white shadow-indigo-600/40' 
                      : 'bg-amber-600 hover:bg-amber-700 text-white shadow-amber-600/40'
                  }`}
                >
                  NEXT LEVEL
                </button>
              )}

              <button 
                onClick={goHome}
                className={`w-full py-4 rounded-2xl border transition-all text-xs uppercase tracking-widest font-black opacity-40 hover:opacity-100 ${
                  isDark 
                    ? 'border-slate-700 text-slate-400 hover:bg-slate-800 hover:text-white' 
                    : 'border-slate-200 text-slate-400 hover:bg-white hover:text-slate-900'
                }`}
              >
                Sector Selection
              </button>

              <button 
                onClick={resetLevel}
                className={`w-full py-4 rounded-2xl border transition-all text-xs uppercase tracking-widest font-black opacity-40 hover:opacity-100 ${
                  isDark 
                    ? 'border-slate-700 text-slate-400 hover:bg-slate-800 hover:text-white' 
                    : 'border-slate-200 text-slate-400 hover:bg-white hover:text-slate-900'
                }`}
              >
                Re-process Grid
              </button>
            </div>
          </div>
        </main>
      </div>
    );
  }

  return (
    <div className={`min-h-screen flex flex-col transition-colors duration-500 ${isDark ? 'text-white' : 'text-slate-900'}`}>
      <Header theme={theme} onToggleTheme={toggleTheme} />

      <main className="flex-grow flex flex-col items-center justify-center p-4">
        <div className="w-full max-w-md flex justify-between items-end mb-8 px-4">
          <button 
            onClick={goHome}
            className={`flex items-center space-x-2 text-[10px] font-black uppercase tracking-widest hover:opacity-70 transition-opacity ${isDark ? 'text-indigo-400' : 'text-amber-700'}`}
          >
            <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M10 19l-7-7m0 0l7-7m-7 7h18" />
            </svg>
            <span>Abort</span>
          </button>
          <div className={`text-right glass px-4 py-2 rounded-xl border shadow-sm ${isDark ? 'border-indigo-500/20' : 'border-amber-500/20'}`}>
            <p className={`text-[9px] font-black tracking-[0.2em] uppercase ${isDark ? 'text-indigo-400' : 'text-amber-700'}`}>Sector {game.level} Output</p>
            <p className={`text-3xl font-mono font-bold ${isDark ? 'text-white' : 'text-slate-900'}`}>{game.moves}</p>
          </div>
        </div>

        <div 
          className={`grid gap-3 p-6 glass rounded-[2.5rem] shadow-2xl mb-8 transition-all duration-500 ${
            isDark ? 'border-indigo-500/10 shadow-indigo-500/5' : 'border-white shadow-amber-500/5'
          }`}
          style={{ 
            gridTemplateColumns: `repeat(${game.size}, minmax(0, 1fr))`,
            width: '100%',
            maxWidth: 'min(90vw, 450px)',
            aspectRatio: '1/1'
          }}
        >
          {game.grid.map((row, r) => 
            row.map((cell, c) => {
              const isTarget = game.hint?.targetCell?.[0] === r && game.hint?.targetCell?.[1] === c;

              const activeClass = isDark 
                ? 'bg-gradient-to-br from-indigo-600 to-indigo-400 shadow-indigo-600/40'
                : 'bg-gradient-to-br from-amber-500 to-yellow-400 shadow-amber-600/40';

              const inactiveClass = isDark
                ? 'bg-slate-900/50 border border-slate-800 hover:border-indigo-800/50'
                : 'bg-white border border-slate-200 hover:border-amber-300';

              const targetPulseClass = isTarget ? 'target-pulse' : '';

              return (
                <button
                  key={`${r}-${c}`}
                  onClick={() => toggleCell(r, c)}
                  className={`
                    relative rounded-2xl transition-all duration-500 transform active:scale-90 overflow-hidden
                    ${cell ? activeClass : inactiveClass}
                    ${targetPulseClass}
                  `}
                >
                  <div className={`absolute inset-0 bg-white/20 transition-opacity duration-500 ${cell ? 'opacity-100' : 'opacity-0'}`} />
                  {isTarget && (
                    <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                       <div className={`w-3 h-3 rounded-full shadow-lg border-2 border-white ${isDark ? 'bg-indigo-400' : 'bg-amber-900'}`} />
                    </div>
                  )}
                </button>
              );
            })
          )}
        </div>

        <div className="w-full max-w-md space-y-4 px-2">
          <div className="grid grid-cols-2 gap-4">
            <button 
              onClick={resetLevel}
              className={`py-4 rounded-2xl border transition-all text-[10px] uppercase tracking-widest font-black shadow-sm ${
                isDark 
                  ? 'border-slate-800 bg-slate-900/50 text-slate-500 hover:text-white hover:bg-slate-800' 
                  : 'border-slate-200 bg-white text-slate-500 hover:text-slate-900 hover:bg-slate-50'
              }`}
            >
              Reset
            </button>
            <button 
              onClick={handleUndo}
              disabled={history.length === 0}
              className={`py-4 rounded-2xl border transition-all text-[10px] uppercase tracking-widest font-black shadow-sm disabled:opacity-20 disabled:cursor-not-allowed ${
                isDark 
                  ? 'border-slate-800 bg-slate-900/50 text-slate-500 hover:text-white hover:bg-slate-800' 
                  : 'border-slate-200 bg-white text-slate-500 hover:text-slate-900 hover:bg-slate-50'
              }`}
            >
              Undo
            </button>
          </div>

          <button 
            onClick={handleGetHint}
            disabled={loadingHint}
            className={`w-full py-5 rounded-2xl font-black border flex items-center justify-center gap-2 transition-all text-xs uppercase tracking-widest ${
              isDark 
                ? 'bg-indigo-600/5 hover:bg-indigo-600/10 text-indigo-400 border-indigo-600/20 shadow-indigo-500/5' 
                : 'bg-amber-600/5 hover:bg-amber-600/10 text-amber-700 border-amber-600/20 shadow-amber-500/5'
            }`}
          >
            {loadingHint ? (
              <div className={`w-5 h-5 border-2 border-t-transparent rounded-full animate-spin ${isDark ? 'border-indigo-500' : 'border-amber-600'}`} />
            ) : (
              <>
                <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
                </svg>
                Sync Hint
              </>
            )}
          </button>
        </div>
      </main>

      <footer className="py-8" />
    </div>
  );
};

